(1, 'AI 与大模型技术前沿讲座', 'academic', '本次讲座邀请业界专家，介绍大模型在软件工程、教育等领域的最新应用与发展趋势，适合对 AI 感兴趣的同学参加。现场留提问时间。', '2026-07-15 14:00:00.000', '2026-07-15 16:00:00.000', '软件大楼 A101', 'T001', '软件学院', 'https://picsum.photos/seed/ai-lecture/800/400', 120, 87, 43, 585, 67, 68.91, 'published', '["AI","编程"]', 'AI2026'),
(2, '校园羽毛球友谊赛', 'sports', '面向全校师生的羽毛球双打友谊赛，按学院分组，优胜队伍将获得精美奖品。请提前热身，穿运动服参赛。', '2026-07-20 09:00:00.000', '2026-07-20 12:00:00.000', '体育馆羽毛球场', '524030910002', '计算机学院', 'https://picsum.photos/seed/badminton/800/400', 64, 23, 14, 265, 18, 20.98, 'published', '["羽毛球","体育运动"]', 'BD2026'),
(3, '摄影社户外采风活动', 'club', '摄影社组织校园及周边人文采风，专业学长带队讲解构图与后期技巧，欢迎零基础同学加入。', '2026-07-18 08:00:00.000', '2026-07-18 17:00:00.000', '图书馆前广场集合', '524030910001', '软件学院', 'https://picsum.photos/seed/photo-club/800/400', 30, 20, 13, 182, 16, 18.38, 'published', '["摄影","艺术"]', 'PH2026'),
(4, '程序设计竞赛训练营', 'innovation', '为期一周的算法与数据结构强化训练，涵盖动态规划、图论等高频考点，为 ACM/ICPC 及各类编程竞赛做准备。', '2026-07-10 19:00:00.000', '2026-07-10 21:00:00.000', '计算机楼 302 实验室', '524030920206', '计算机学院', 'https://picsum.photos/seed/act4/800/400', 50, 30, 15, 415, 24, 27.98, 'ended', '["编程","AI"]', 'IN0004'),
(5, '校园志愿者招募 — 社区服务日', 'volunteer', '组织同学前往周边社区开展助老、环境清洁等志愿服务，可计入志愿服务时长，欢迎热心公益的同学报名。', '2026-07-27 08:00:00.000', '2026-07-27 15:30:00.000', '校门口集合', '525030920043', '软件学院', 'https://picsum.photos/seed/act5/800/400', 40, 10, 3, 119, 0, 6.22, 'published', '["志愿服务"]', 'VO0005'),
(6, '校园音乐节 — 夏日之声', 'arts', '各社团及个人歌手同台演出，涵盖流行、摇滚、民谣等多种风格，现场还有互动抽奖环节。', '2026-08-13 18:00:00.000', '2026-08-13 21:00:00.000', '中心广场', '523030920201', '计算机学院', 'https://picsum.photos/seed/act6/800/400', 500, 293, 173, 2669, 0, 196.4, 'published', '["音乐","文艺"]', 'AR0006'),
(7, '三人篮球校园联赛', 'sports', '3v3 街头篮球赛，开赛前有热身教学，适合各类水平球员。强对抗、快节奏，欢迎组队参赛。', '2026-08-30 15:00:00.000', '2026-08-30 19:00:00.000', '室外篮球场', '522030920188', '经济管理学院', 'https://picsum.photos/seed/act7/800/400', 48, 19, 8, 257, 0, 14.15, 'published', '["篮球","体育运动"]', 'SP0007'),
(8, '量子信息与量子计算导论', 'academic', '从量子比特与纠缠讲起，介绍近期实验进展。需具备一定线性代数与概率基础。', '2026-05-09 19:00:00.000', '2026-05-09 21:00:00.000', '物理楼演示厅', '523030920161', '人文学院', 'https://picsum.photos/seed/act8/800/400', 100, 89, 35, 659, 70, 69.12, 'ended', '["物理","学术"]', 'AC0008'),
(9, '烘焙社 — 周末手工饼干工作坊', 'club', '亲手完成一盒黄油曲奇，学习称量、搅拌与烤箱温度控制。材料现场提供。', '2026-05-26 14:00:00.000', '2026-05-26 17:00:00.000', '学生活动中心厨房', '523030920197', '数学学院', 'https://picsum.photos/seed/act9/800/400', 20, 10, 2, 225, 8, 10.85, 'ended', '["烘焙","休闲"]', 'CL0009'),
(10, '校际辩论邀请赛选拔', 'academic', '进行立论、质询与结辩训练，最终选拔代表队参加校际赛。锻炼逻辑与临场应变。', '2026-06-12 18:00:00.000', '2026-06-12 20:30:00.000', '教学楼 B203', '523030920149', '电子学院', 'https://picsum.photos/seed/act10/800/400', 40, 19, 10, 232, 13, 16.98, 'ended', '["辩论","表达"]', 'AC0010'),
(11, '大学生创业路演夜', 'innovation', '创业团队 8 分钟路演 + 导师点评，主题涵盖校园服务与教具硬件。寻找合伙人或早期用户的同学欢迎观摩。', '2026-06-29 18:00:00.000', '2026-06-29 21:00:00.000', '创业孵化中心', '522030920192', '电子学院', 'https://picsum.photos/seed/act11/800/400', 80, 68, 37, 506, 44, 53.14, 'ended', '["创业","创新"]', 'IN0011'),
(12, '心理健康工作坊 — 压力与放松', 'club', '循证放松练习、正念呼吸与情绪日记分享，帮助缓解备考与实习压力。小班引导，注重隐私。', '2026-07-16 16:00:00.000', '2026-07-16 18:00:00.000', '心理中心团体室', '524030920126', '电子学院', 'https://picsum.photos/seed/act12/800/400', 25, 7, 3, 212, 0, 7.82, 'published', '["心理","放松"]', 'CL0012'),
(13, '书法社团钢笔字入门课', 'arts', '临摹楷书基本笔画与结构，适合想把笔记写工整、培养静心习惯的同学。', '2026-08-02 19:00:00.000', '2026-08-02 21:00:00.000', '文科楼书画室', '523030920209', '人文学院', 'https://picsum.photos/seed/act13/800/400', 28, 13, 4, 153, 0, 8.01, 'published', '["书法","文艺"]', 'AR0013'),
(14, '机器人兴趣小组调试日', 'innovation', '轮式小车传感器校准与路径跟踪 demo，组队完成迷宫闯关。欢迎电子、机械与编程方向混合组队。', '2026-08-19 09:00:00.000', '2026-08-19 17:00:00.000', '工训中心 B区', '522030920128', '信息学院', 'https://picsum.photos/seed/act14/800/400', 36, 27, 10, 273, 0, 18.02, 'published', '["机器人","编程"]', 'IN0014'),
(15, '英语角 — Movie Night 观影畅谈', 'club', '英文电影片段赏析后分组讨论剧情与角色，轻松练习口语。无需口语达人。', '2026-09-05 19:00:00.000', '2026-09-05 21:00:00.000', '国际交流中心', '524030920086', '机械学院', 'https://picsum.photos/seed/act15/800/400', 35, 22, 13, 317, 0, 16.3, 'published', '["英语","交流"]', 'CL0015'),
